# ── DATA ──────────────────────────────────────────────────────────────────────
@st.cache_data
def load_data():
    def parse_csv(path):
        df = pd.read_csv(path, sep=';', decimal=',', low_memory=False)
        for col in df.columns:
            if col not in ['Player','Short Name','Team','Competition','Season',
                           'Position Group','Birthdate','Player ID','Team ID',
                           'Competition ID','Season ID']:
                df[col] = pd.to_numeric(df[col], errors='coerce')
        df = df.copy()
        df['position'] = df['Position Group'].map(POS_MAP)
        df['season']   = df['Season'].str[:4]
        df['total_minutes'] = (
            df['Minutes'].fillna(0) *
            df['Count Performances (Physical Check passed)'].fillna(0)
        ).round(0).astype(int)
        if 'Birthdate' in df.columns:
            df['birthdate'] = pd.to_datetime(df['Birthdate'], errors='coerce')
            df['age'] = ((pd.Timestamp('today') - df['birthdate']).dt.days / 365.25).apply(
                lambda x: round(x, 1) if pd.notna(x) else np.nan)
        else:
            df['age'] = np.nan
        return df

    vk = parse_csv("veikkausliiga.csv")
    t5 = parse_csv("top5.csv") if os.path.exists("top5.csv") else None
    return vk, t5

def build_scores_df(bench_df_local):
    """Build scores DataFrame for all VK players vs given benchmark."""
    rows = []
    for _, player in vk.iterrows():
        pos = player.get('position')
        if not pos: continue
        sc, _, prof = player_card(player, bench_df_local)
        rows.append({
            'Player':        player.get('Player','—'),
            'Team':          player.get('Team','—'),
            'Position':      POS_EN.get(pos,pos),
            'Season':        player.get('season','—'),
            'Age':           player.get('age', np.nan),
            'Minutes':       int(player.get('total_minutes',0) or 0),
            'speed':         sc.get('speed',np.nan),
            'burst':         sc.get('burst',np.nan),
            'otip':          sc.get('otip', np.nan),
            'bip':           sc.get('bip',  np.nan),
            'Profile':       prof,
            '_pos':          pos,
            '_season':       player.get('season','—'),
            '_total_minutes':int(player.get('total_minutes',0) or 0),
            '_age':          player.get('age', np.nan),
        })
    return pd.DataFrame(rows)

vk, t5 = load_data()

def get_scores_df(bench_source):
    """Get cached scores — uses session_state keyed by bench_source."""
    key = f"scores_{bench_source}"
    if key not in st.session_state:
        if bench_source == "t5" and t5 is not None:
            # Ensure t5 numeric columns converted
            t5_num = t5.copy()
            for col in t5_num.columns:
                if col not in ['Player','Short Name','Team','Competition','Season',
                               'Position Group','Birthdate','Player ID','Team ID',
                               'Competition ID','Season ID','position','season','total_minutes','age']:
                    t5_num[col] = pd.to_numeric(t5_num[col], errors='coerce')
            st.session_state[key] = build_scores_df(t5_num)
        else:
            st.session_state[key] = build_scores_df(vk)
    return st.session_state[key]

def calc_all_scores(vk_hash, bench_source, t5_hash="none"):
    return get_scores_df(bench_source)

# ── CALC FUNCTIONS ────────────────────────────────────────────────────────────
def calc_layer_scores(player_row, bench_df, position):
    metrics = get_layer_metrics()
    results = {}
    bench   = bench_df[bench_df['position'] == position]

    for layer, cols in metrics.items():
        layer_data = []
        for col, name, unit, higher_better in cols:
            if col not in bench.columns: continue
            bench_vals = bench[col].dropna()
            val = player_row.get(col, np.nan)
            if pd.isna(val) or len(bench_vals) < 3: continue
            pct = float((bench_vals < val).sum()) / len(bench_vals) * 100 if higher_better                   else float((bench_vals > val).sum()) / len(bench_vals) * 100
            layer_data.append((col, name, unit, float(val), round(pct,1), higher_better))
        results[layer] = layer_data
    return results

def layer_score(data):
    vals = [d[4] for d in data]
    return round(np.mean(vals), 1) if vals else np.nan

def render_bar(name, val, pct, unit, color):
    return f"""<div class="metric-row">
        <div class="metric-name">{name}</div>
        <div class="metric-bar-bg">
            <div class="metric-bar-fill" style="width:{pct:.0f}%;background:{color};"></div>
        </div>
        <div class="metric-val">{val:.2f} {unit}</div>
        <div class="metric-pct">{pct:.0f}%</div>
    </div>"""

def player_card(player_row, bench_df, benchmark_label="Veikkausliiga"):
    pos    = player_row.get('position')
    all_data = calc_layer_scores(player_row, bench_df, pos)
    scores   = {l: layer_score(d) for l,d in all_data.items()}
    s = scores.get('speed',0) or 0
    b = scores.get('burst',0) or 0
    o = scores.get('otip', 0) or 0
    p = scores.get('bip',  0) or 0
    return scores, all_data, get_profile(s,b,o,p)

